-- 注意注意******组态v2.0对应主系统v2.4版本，主系统v2.4之前的版本不可用******
-- 注意：不管主系统是哪个版本，以下表结构一定要整合到主系统sql文件里，或者单独在数据库执行
-- 如果主系统是使用v2.4脚本sql执行的，注意不要完全复制该scadav2.0脚本执行，需要把该脚本下面的‘菜单’、‘字典’sql删除，下面已有注释说明
-- 组态表结构

CREATE TABLE "public"."scada" (
                                  "id" int8 NOT NULL,
                                  "guid" varchar(128) COLLATE "pg_catalog"."default",
                                  "scada_data" text COLLATE "pg_catalog"."default",
                                  "serial_numbers" varchar(50) COLLATE "pg_catalog"."default",
                                  "device_name" varchar(128) COLLATE "pg_catalog"."default",
                                  "is_main_page" int4,
                                  "page_name" varchar(20) COLLATE "pg_catalog"."default",
                                  "page_resolution" varchar(20) COLLATE "pg_catalog"."default",
                                  "is_share" int4 DEFAULT 0,
                                  "share_url" text COLLATE "pg_catalog"."default",
                                  "share_pass" varchar(50) COLLATE "pg_catalog"."default",
                                  "page_image" varchar(2000) COLLATE "pg_catalog"."default",
                                  "tenant_id" int8,
                                  "tenant_name" varchar(30) COLLATE "pg_catalog"."default",
                                  "create_by" varchar(50) COLLATE "pg_catalog"."default",
                                  "create_time" timestamp(6) NOT NULL DEFAULT CURRENT_TIMESTAMP,
                                  "update_by" varchar(50) COLLATE "pg_catalog"."default",
                                  "update_time" timestamp(6) NOT NULL DEFAULT CURRENT_TIMESTAMP,
                                  "del_flag" int2 NOT NULL DEFAULT 0,
                                  "remark" varchar(800) COLLATE "pg_catalog"."default",
                                  "type" int2,
                                  "share_short_url" text COLLATE "pg_catalog"."default",
                                  CONSTRAINT "scada_pkey" PRIMARY KEY ("id")
)
;

COMMENT ON COLUMN "public"."scada"."id" IS 'id唯一标识';

COMMENT ON COLUMN "public"."scada"."guid" IS '组态id';

COMMENT ON COLUMN "public"."scada"."scada_data" IS '组态信息';

COMMENT ON COLUMN "public"."scada"."serial_numbers" IS '设备编号';

COMMENT ON COLUMN "public"."scada"."device_name" IS '设备名称';

COMMENT ON COLUMN "public"."scada"."is_main_page" IS '是否主界面';

COMMENT ON COLUMN "public"."scada"."page_name" IS '页面名称';

COMMENT ON COLUMN "public"."scada"."page_resolution" IS '页面大小';

COMMENT ON COLUMN "public"."scada"."is_share" IS '是否分享';

COMMENT ON COLUMN "public"."scada"."share_url" IS '分享链接';

COMMENT ON COLUMN "public"."scada"."share_pass" IS '分享密码';

COMMENT ON COLUMN "public"."scada"."page_image" IS '页面图片';

COMMENT ON COLUMN "public"."scada"."tenant_id" IS '租户id';

COMMENT ON COLUMN "public"."scada"."tenant_name" IS '租户名称';

COMMENT ON COLUMN "public"."scada"."create_by" IS '创建人';

COMMENT ON COLUMN "public"."scada"."create_time" IS '创建时间';

COMMENT ON COLUMN "public"."scada"."update_by" IS '更新人';

COMMENT ON COLUMN "public"."scada"."update_time" IS '更新时间';

COMMENT ON COLUMN "public"."scada"."del_flag" IS '逻辑删除标识';

COMMENT ON COLUMN "public"."scada"."remark" IS '备注';

COMMENT ON COLUMN "public"."scada"."type" IS '组态类型 1- 模板组态 2- 场景组态 3-公共组态';

COMMENT ON COLUMN "public"."scada"."share_short_url" IS '分享短链接';

COMMENT ON TABLE "public"."scada" IS '组态页面';

